529: // Validate returns error if given scrape protocol is not supported.
530: func (s ScrapeProtocol) Validate() error {
531: 	if _, ok := ScrapeProtocolsHeaders[s]; !ok {
532: 		return fmt.Errorf("unknown scrape protocol %v, supported: %v",
533: 			s, func() (ret []string) {
534: 				for k := range ScrapeProtocolsHeaders {
535: 					ret = append(ret, string(k))
536: 				}
537: 				sort.Strings(ret)
538: 				return ret
539: 			}())
540: 	}
541: 	return nil
542: }
