594: // validateAcceptScrapeProtocols return errors if we see problems with accept scrape protocols option.
595: func validateAcceptScrapeProtocols(sps []ScrapeProtocol) error {
596: 	if len(sps) == 0 {
597: 		return errors.New("scrape_protocols cannot be empty")
598: 	}
599: 	dups := map[string]struct{}{}
600: 	for _, sp := range sps {
601: 		if _, ok := dups[strings.ToLower(string(sp))]; ok {
602: 			return fmt.Errorf("duplicated protocol in scrape_protocols, got %v", sps)
603: 		}
604: 		if err := sp.Validate(); err != nil {
605: 			return fmt.Errorf("scrape_protocols: %w", err)
606: 		}
607: 		dups[strings.ToLower(string(sp))] = struct{}{}
608: 	}
609: 	return nil
610: }
